import pytest
from source import longest_common_subsequence

def test_longest_common_subsequence_returns_valid_lcs():
    def is_subsequence(subseq, seq):
        it = iter(seq)
        return all(c in it for c in subseq)

    result = longest_common_subsequence('AGCAT', 'GAC')
    assert is_subsequence(result, 'AGCAT'), f"'{result}' is not a valid subsequence of 'AGCAT'"
    assert is_subsequence(result, 'GAC'), f"'{result}' is not a valid subsequence of 'GAC'"

from source import longest_common_subsequence

def test_longest_common_subsequence_valid_subsequences():
