    def is_subsequence(subseq, seq):
        it = iter(seq)
        return all(c in it for c in subseq)

    assert is_subsequence(result, 'AA'), f"LCS '{result}' is not a valid subsequence of 'AA'"
    assert is_subsequence(result, 'A'), f"LCS '{result}' is not a valid subsequence of 'A'"
